    "            /* Mode 6 KPASS: key = data (private = post-rule password). */\n"
    "            klen = len;\n"
    "            mlen = (int)slen;\n"
    "            if (klen > 64) {\n"
    "                uint kstate[8] = { 0x6a09e667u, 0xbb67ae85u, 0x3c6ef372u,\n"
    "                                   0xa54ff53au, 0x510e527fu, 0x9b05688cu,\n"
    "                                   0x1f83d9abu, 0x5be0cd19u };\n"
    "                uint kM[16];\n"
    "                int copy1 = (klen < 64) ? klen : 64;\n"
    "                for (int i = 0; i < 16; i++) kM[i] = 0;\n"
    "                for (int i = 0; i < copy1; i++) {\n"
    "                    uint v = (uint)data[i];\n"
    "                    kM[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                }\n"
    "                if (klen <= 55) {\n"
    "                    kM[klen >> 2] |= ((uint)0x80u) << ((3 - (klen & 3)) * 8);\n"
    "                    kM[14] = 0;\n"
    "                    kM[15] = (uint)klen * 8u;\n"
    "                }\n"
    "                sha1_block(&kstate[0], kM);\n"
    "                if (klen > 55) {\n"
    "                    for (int i = 0; i < 16; i++) kM[i] = 0;\n"
    "                    int rem = klen - 64;\n"
    "                    if (rem > 0) {\n"
    "                        for (int i = 0; i < rem; i++) {\n"
    "                            uint v = (uint)data[64 + i];\n"
    "                            kM[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                        }\n"
    "                    }\n"
    "                    {\n"
    "                        int p = (rem > 0) ? rem : 0;\n"
    "                        kM[p >> 2] |= ((uint)0x80u) << ((3 - (p & 3)) * 8);\n"
    "                    }\n"
    "                    kM[14] = 0;\n"
    "                    kM[15] = (uint)klen * 8u;\n"
    "                    sha1_block(&kstate[0], kM);\n"
    "                }\n"
    "                for (int i = 0; i < 8; i++) key_block[i] = bswap32(kstate[i]);\n"
    "                klen = 32;\n"
    "            } else {\n"
    "                for (int i = 0; i < klen; i++) {\n"
    "                    uint v = (uint)data[i];\n"
    "                    key_block[i >> 2] |= v << ((i & 3) * 8);\n"
    "                }\n"
    "            }\n"
    "        }\n"
    "\n"
    "        /* Step 2: inner = SHA256((key ^ ipad) || message). The key_block\n"
    "         * is uint LE; XOR with 0x36363636u then bswap32 to BE for sha256_-\n"
    "         * block. Slab oracle line 83-92 / 203-211. */\n"
    "        uint ipad[16];\n"
    "        uint hm[16];\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            ipad[i] = key_block[i] ^ 0x36363636u;\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            hm[i] = bswap32(ipad[i]);\n"
    "\n"
    "        uint istate[8] = { 0x6a09e667u, 0xbb67ae85u, 0x3c6ef372u,\n"
    "                           0xa54ff53au, 0x510e527fu, 0x9b05688cu,\n"
    "                           0x1f83d9abu, 0x5be0cd19u };\n"
    "        sha1_block(&istate[0], hm);\n"
    "\n"
    "        /* Continue with message bytes + 0x80 + length; total = 64 (ipad)\n"
    "         * + mlen. SHA256 BE byte-pack. */\n"
    "        if (algo_mode == 5u) {\n"
    "            /* msg = data (private). Slab oracle line 95-112. */\n"
    "            if (mlen <= 55) {\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < mlen; i++) {\n"
    "                    uint v = (uint)data[i];\n"
    "                    hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                }\n"
    "                hm[mlen >> 2] |= ((uint)0x80u) << ((3 - (mlen & 3)) * 8);\n"
    "                hm[14] = 0;\n"
    "                hm[15] = (uint)(64 + mlen) * 8u;\n"
    "                sha1_block(&istate[0], hm);\n"
    "            } else {\n"
    "                int copy1 = (mlen < 64) ? mlen : 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < copy1; i++) {\n"
    "                    uint v = (uint)data[i];\n"
    "                    hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                }\n"
    "                if (mlen < 64)\n"
    "                    hm[mlen >> 2] |= ((uint)0x80u) << ((3 - (mlen & 3)) * 8);\n"
    "                sha1_block(&istate[0], hm);\n"
    "                int rem = mlen - 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                if (rem > 0) {\n"
    "                    for (int i = 0; i < rem; i++) {\n"
    "                        uint v = (uint)data[64 + i];\n"
    "                        hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                    }\n"
    "                }\n"
    "                if (mlen >= 64) {\n"
    "                    int p = (rem > 0) ? rem : 0;\n"
    "                    hm[p >> 2] |= ((uint)0x80u) << ((3 - (p & 3)) * 8);\n"
    "                }\n"
    "                hm[14] = 0;\n"
    "                hm[15] = (uint)(64 + mlen) * 8u;\n"
    "                sha1_block(&istate[0], hm);\n"
    "            }\n"
    "        } else {\n"
    "            /* Mode 6 KPASS: msg = salt_buf (global). Slab oracle line\n"
    "             * 213-229. */\n"
    "            if (mlen <= 55) {\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < mlen; i++) {\n"
    "                    uint v = (uint)salt_buf[i];\n"
    "                    hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                }\n"
    "                hm[mlen >> 2] |= ((uint)0x80u) << ((3 - (mlen & 3)) * 8);\n"
    "                hm[14] = 0;\n"
    "                hm[15] = (uint)(64 + mlen) * 8u;\n"
    "                sha1_block(&istate[0], hm);\n"
    "            } else {\n"
    "                int copy1 = (mlen < 64) ? mlen : 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < copy1; i++) {\n"
    "                    uint v = (uint)salt_buf[i];\n"
    "                    hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                }\n"
    "                if (mlen < 64)\n"
    "                    hm[mlen >> 2] |= ((uint)0x80u) << ((3 - (mlen & 3)) * 8);\n"
    "                sha1_block(&istate[0], hm);\n"
    "                int rem = mlen - 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                if (rem > 0) {\n"
    "                    for (int i = 0; i < rem; i++) {\n"
    "                        uint v = (uint)salt_buf[64 + i];\n"
    "                        hm[i >> 2] |= v << ((3 - (i & 3)) * 8);\n"
    "                    }\n"
    "                }\n"
    "                if (mlen >= 64) {\n"
    "                    int p = (rem > 0) ? rem : 0;\n"
    "                    hm[p >> 2] |= ((uint)0x80u) << ((3 - (p & 3)) * 8);\n"
    "                }\n"
    "                hm[14] = 0;\n"
    "                hm[15] = (uint)(64 + mlen) * 8u;\n"
    "                sha1_block(&istate[0], hm);\n"
    "            }\n"
    "        }\n"
    "\n"
    "        /* Step 3: outer = SHA256((key ^ opad) || inner_hash). istate[8]\n"
    "         * is BE; all 8 words copied directly into M[0..7]. M[8] =\n"
    "         * 0x80000000u (BE 0x80 at byte 32 = high octet of word 8).\n"
    "         * M[14]=0, M[15] = 768 bits (= 96 bytes * 8). Slab oracle line\n"
    "         * 117-133 / 232-246. */\n"
    "        uint opad_block[16];\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            opad_block[i] = key_block[i] ^ 0x5c5c5c5cu;\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            hm[i] = bswap32(opad_block[i]);\n"
    "\n"
    "        uint ostate[8] = { 0x6a09e667u, 0xbb67ae85u, 0x3c6ef372u,\n"
    "                           0xa54ff53au, 0x510e527fu, 0x9b05688cu,\n"
    "                           0x1f83d9abu, 0x5be0cd19u };\n"
    "        sha1_block(&ostate[0], hm);\n"
    "\n"
    "        for (int i = 0; i < 8; i++) hm[i] = istate[i];\n"
    "        hm[8] = 0x80000000u;\n"
    "        for (int i = 9; i < 15; i++) hm[i] = 0;\n"
    "        hm[14] = 0;\n"
    "        hm[15] = (64u + 32u) * 8u;     /* 768 bits */\n"
    "        sha1_block(&ostate[0], hm);\n"
    "\n"
    "        /* Write final BE state into st->h[0..7] (template_digest_compare\n"
    "         * bswaps 4 leading words to LE for compact-table probe; emit_hit\n"
    "         * bswaps all 8 words for hits buffer). SHA256 emits the full\n"
    "         * 8-word digest — no truncation (unlike SHA224 which drops h[7]). */\n"
    "        for (int i = 0; i < 8; i++) st->h[i] = ostate[i];\n"
    "        return;\n"
    "    }\n"
    "\n"
    "    /* Process complete 64-byte blocks. Build M[] BIG-ENDIAN directly\n"
    "     * from bytes; salt bytes for p < slen, password bytes for p >= slen. */\n"
    "    while (total_len - pos >= HASH_BLOCK_BYTES) {\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "        for (int i = 0; i < HASH_BLOCK_BYTES; i++) {\n"
    "            int p = pos + i;\n"
    "            uchar c;\n"
    "            if (p < (int)slen) {\n"
    "                c = salt_buf[p];\n"
    "            } else {\n"
    "                c = data[p - (int)slen];\n"
    "            }\n"
    "            M[i >> 2] |= ((uint)c) << ((3 - (i & 3)) * 8);\n"
    "        }\n"
    "        sha1_block(&st->h[0], M);\n"
    "        pos += HASH_BLOCK_BYTES;\n"
    "    }\n"
    "\n"
    "    /* Build final block(s): tail bytes + 0x80 marker + zeros + 64-bit\n"
    "     * BE length. */\n"
    "    int rem = total_len - pos;  /* 0..63 */\n"
    "    for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "    for (int i = 0; i < rem; i++) {\n"
    "        int p = pos + i;\n"
    "        uchar c;\n"
    "        if (p < (int)slen) {\n"
    "            c = salt_buf[p];\n"
    "        } else {\n"
    "            c = data[p - (int)slen];\n"
    "        }\n"
    "        M[i >> 2] |= ((uint)c) << ((3 - (i & 3)) * 8);\n"
    "    }\n"
    "    /* 0x80 padding marker, BE byte position. */\n"
    "    M[rem >> 2] |= ((uint)0x80u) << ((3 - (rem & 3)) * 8);\n"
    "\n"
    "    if (rem < 56) {\n"
    "        /* Length fits in this block. SHA-family BE: M[14] = high 32\n"
    "         * bits of bit count, M[15] = low 32 bits. For total_len < 2^29\n"
    "         * bytes (always true for our wordlist+salt inputs), high 32\n"
    "         * bits = 0. */\n"
    "        M[14] = 0;\n"
    "        M[15] = (uint)((uint)total_len * 8u);\n"
    "        sha1_block(&st->h[0], M);\n"
    "    } else {\n"
    "        /* Need one extra padding-only block to hold the length. */\n"
    "        sha1_block(&st->h[0], M);\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "        M[14] = 0;\n"
    "        M[15] = (uint)((uint)total_len * 8u);\n"
    "        sha1_block(&st->h[0], M);\n"
    "    }\n"
    "}\n"
    "\n"
    "/* template_iterate: -i loop step. Re-encode the digest as 40-byte\n"
    " * lowercase hex ASCII and rehash with fresh IV. lowercase hex of prior 40-char digest re-SHA1'd with FRESH IV (no salt re-application). Lines 14411-14412: prmd5(curin.h, newbuf, 40); mysha1(newbuf, 40, ...). Identical iter shape to MD5SALTPASS but with SHA1 + 40-char hex (vs 32-char for MD5).\n"
    " *\n"
    " * Mirrors gpu_sha1_core.cl rev 1 lines 257-288 byte-for-byte:\n"
    " *   - 5 state words -> 10 BE-encoded hex M[] words (2 words per state\n"
    " *     word, 4 hex chars each)\n"
    " *   - M[10] = 0x80000000u   (BE 0x80 padding at byte offset 40)\n"
    " *   - M[11..14] = 0\n"
    " *   - M[15] = 40 * 8 = 320 (bit count)\n"
    " *   - state reset to SHA1 IV; sha1_block. */\n"
    "static inline void template_iterate(template_state *st)\n"
    "{\n"
    "    uint M[16];\n"
    "    /* Inlined sha1_to_hex_lc_p body — keeps this core self-contained\n"
    "     * (gpu_sha1_packed.cl's hex_byte_be_p / sha1_to_hex_lc_p are not\n"
    "     * exported through gpu_common.cl). Per-byte BE hex encoding. */\n"
    "    for (int i = 0; i < 5; i++) {\n"
    "        uint s = st->h[i];\n"
    "        uint b0 = (s >> 24) & 0xff;\n"
    "        uint b1 = (s >> 16) & 0xff;\n"
    "        uint b2 = (s >> 8)  & 0xff;\n"
    "        uint b3 = s & 0xff;\n"
    "        uint hi0 = (b0 >> 4) & 0xf, lo0 = b0 & 0xf;\n"
    "        uint hi1 = (b1 >> 4) & 0xf, lo1 = b1 & 0xf;\n"
    "        uint hi2 = (b2 >> 4) & 0xf, lo2 = b2 & 0xf;\n"
    "        uint hi3 = (b3 >> 4) & 0xf, lo3 = b3 & 0xf;\n"
    "        uint h0 = ((hi0 + ((hi0 < 10) ? '0' : ('a' - 10))) << 8)\n"
    "                |  (lo0 + ((lo0 < 10) ? '0' : ('a' - 10)));\n"
    "        uint h1 = ((hi1 + ((hi1 < 10) ? '0' : ('a' - 10))) << 8)\n"
    "                |  (lo1 + ((lo1 < 10) ? '0' : ('a' - 10)));\n"
    "        uint h2 = ((hi2 + ((hi2 < 10) ? '0' : ('a' - 10))) << 8)\n"
    "                |  (lo2 + ((lo2 < 10) ? '0' : ('a' - 10)));\n"
    "        uint h3 = ((hi3 + ((hi3 < 10) ? '0' : ('a' - 10))) << 8)\n"
    "                |  (lo3 + ((lo3 < 10) ? '0' : ('a' - 10)));\n"
    "        M[i * 2]     = (h0 << 16) | h1;\n"
    "        M[i * 2 + 1] = (h2 << 16) | h3;\n"
    "    }\n"
    "    M[10] = 0x80000000u;\n"
    "    for (int j = 11; j < 15; j++) M[j] = 0u;\n"
    "    M[15] = 40u * 8u;        /* 40 hex chars = 320 bits */\n"
    "    /* Reinitialize state to SHA1 IV, then absorb the prepared M[]. */\n"
    "    st->h[0] = 0x67452301u;\n"
    "    st->h[1] = 0xEFCDAB89u;\n"
    "    st->h[2] = 0x98BADCFEu;\n"
    "    st->h[3] = 0x10325476u;\n"
    "    st->h[4] = 0xC3D2E1F0u;\n"
    "    sha1_block(&st->h[0], M);\n"
    "}\n"
    "\n"
    "/* template_digest_compare: probe the compact table with the final digest.\n"
    " * SHA1 state is BE; bswap leading 4 words to LE (host's compact_table key\n"
    " * encoding). The 5th state word is NOT used by the compact-table probe —\n"
    " * only by EMIT_HIT_5 below. */\n"
    "static inline int template_digest_compare(\n"
    "    const template_state *st,\n"
    "    __global const uint *compact_fp, __global const uint *compact_idx,\n"
    "    ulong compact_mask, uint max_probe, uint hash_data_count,\n"
    "    __global const uchar *hash_data_buf, __global const ulong *hash_data_off,\n"
    "    __global const ulong *overflow_keys, __global const uchar *overflow_hashes,\n"
    "    __global const uint *overflow_offsets, uint overflow_count,\n"
    "    uint *out_idx)\n"
    "{\n"
    "    uint h0 = bswap32(st->h[0]);\n"
    "    uint h1 = bswap32(st->h[1]);\n"
    "    uint h2 = bswap32(st->h[2]);\n"
    "    uint h3 = bswap32(st->h[3]);\n"
    "    return probe_compact_idx(\n"
    "        h0, h1, h2, h3,\n"
    "        compact_fp, compact_idx,\n"
    "        compact_mask, max_probe, hash_data_count,\n"
    "        hash_data_buf, hash_data_off,\n"
    "        overflow_keys, overflow_hashes, overflow_offsets, overflow_count,\n"
    "        out_idx);\n"
    "}\n"
    "\n"
    "/* template_emit_hit: emit a hit into the global hits buffer. Wraps\n"
    " * EMIT_HIT_5. Hits buffer convention matches gpu_sha1_core.cl /\n"
    " * gpu_sha1_packed.cl: 5 LE-byteswapped digest words after the\n"
    " * widx/sidx/iter triple. */\n"
    "#define template_emit_hit(hits, hit_count, max_hits, st, widx, sidx, iter) \\\n"
    "    do { \\\n"
    "        uint _h[5]; \\\n"
    "        _h[0] = bswap32((st)->h[0]); \\\n"
    "        _h[1] = bswap32((st)->h[1]); \\\n"
    "        _h[2] = bswap32((st)->h[2]); \\\n"
    "        _h[3] = bswap32((st)->h[3]); \\\n"
    "        _h[4] = bswap32((st)->h[4]); \\\n"
    "        EMIT_HIT_5((hits), (hit_count), (max_hits), \\\n"
    "                   (widx), (sidx), (iter), _h) \\\n"
    "    } while (0)\n"
    "\n"
    "/* B3 dedup+overflow-aware variant. See gpu_sha1_core.cl for protocol\n"
    " * notes. */\n"
    "#define template_emit_hit_or_overflow(hits, hit_count, max_hits, st, widx, sidx, iter, \\\n"
    "                                      hashes_shown, matched_idx, dedup_mask, \\\n"
    "                                      ovr_set, ovr_gid, lane_gid) \\\n"
    "    do { \\\n"
    "        uint _h[5]; \\\n"
    "        _h[0] = bswap32((st)->h[0]); \\\n"
    "        _h[1] = bswap32((st)->h[1]); \\\n"
    "        _h[2] = bswap32((st)->h[2]); \\\n"
    "        _h[3] = bswap32((st)->h[3]); \\\n"
    "        _h[4] = bswap32((st)->h[4]); \\\n"
    "        EMIT_HIT_5_DEDUP_OR_OVERFLOW((hits), (hit_count), (max_hits), \\\n"
    "                   (widx), (sidx), (iter), _h, \\\n"
    "                   (hashes_shown), (matched_idx), (dedup_mask), \\\n"
    "                   (ovr_set), (ovr_gid), (lane_gid)); \\\n"
    "    } while (0)\n"
;
